// CLI integration tests: spawn the script as a subprocess and assert on
// its stdout, stderr, and exit code. Uses bundled fixtures plus a mocked
// license database so no network access is needed.
import { describe, expect, test } from "bun:test";
import { spawnSync } from "bun";
import { existsSync, mkdirSync, writeFileSync, rmSync } from "node:fs";
import { join } from "node:path";

const tmpRoot = join(import.meta.dir, "tmp-cli");
const cliPath = join(import.meta.dir, "..", "src", "cli.ts");

function setupCase(name: string, files: Record<string, string>): string {
  const dir = join(tmpRoot, name);
  if (existsSync(dir)) rmSync(dir, { recursive: true, force: true });
  mkdirSync(dir, { recursive: true });
  for (const [filename, content] of Object.entries(files)) {
    writeFileSync(join(dir, filename), content);
  }
  return dir;
}

const policy = {
  allow: ["MIT", "Apache-2.0", "BSD-3-Clause"],
  deny: ["GPL-3.0"],
};

const licenses = {
  lodash: "MIT",
  express: "MIT",
  "evil-pkg": "GPL-3.0",
  "weird-pkg": "WTFPL",
};

describe("CLI", () => {
  test("succeeds (exit 0) when no denied dependencies are found", () => {
    const dir = setupCase("happy", {
      "package.json": JSON.stringify({
        dependencies: { lodash: "1.0.0", express: "4.18.2" },
      }),
      "policy.json": JSON.stringify(policy),
      "licenses.json": JSON.stringify(licenses),
    });

    const result = spawnSync({
      cmd: [
        "bun",
        "run",
        cliPath,
        "--manifest",
        "package.json",
        "--policy",
        "policy.json",
        "--licenses",
        "licenses.json",
        "--format",
        "text",
      ],
      cwd: dir,
    });

    const stdout = result.stdout.toString();
    expect(result.exitCode).toBe(0);
    expect(stdout).toContain("[APPROVED]");
    expect(stdout).toContain("Summary: total=2 approved=2 denied=0 unknown=0");
  });

  test("exits non-zero when a denied or unknown license is found", () => {
    const dir = setupCase("denied", {
      "package.json": JSON.stringify({
        dependencies: { "evil-pkg": "1.0.0", "weird-pkg": "1.0.0" },
      }),
      "policy.json": JSON.stringify(policy),
      "licenses.json": JSON.stringify(licenses),
    });

    const result = spawnSync({
      cmd: [
        "bun",
        "run",
        cliPath,
        "--manifest",
        "package.json",
        "--policy",
        "policy.json",
        "--licenses",
        "licenses.json",
        "--format",
        "text",
      ],
      cwd: dir,
    });

    expect(result.exitCode).toBe(2);
    const stdout = result.stdout.toString();
    expect(stdout).toContain("[DENIED]");
    expect(stdout).toContain("[UNKNOWN]");
    expect(stdout).toContain("Summary: total=2 approved=0 denied=1 unknown=1");
  });

  test("emits a meaningful error when the manifest is missing", () => {
    const dir = setupCase("missing", {
      "policy.json": JSON.stringify(policy),
      "licenses.json": JSON.stringify(licenses),
    });

    const result = spawnSync({
      cmd: [
        "bun",
        "run",
        cliPath,
        "--manifest",
        "package.json",
        "--policy",
        "policy.json",
        "--licenses",
        "licenses.json",
      ],
      cwd: dir,
    });

    expect(result.exitCode).not.toBe(0);
    const stderr = result.stderr.toString();
    expect(stderr).toMatch(/manifest .* not found/i);
  });

  test("--format json emits parseable JSON on stdout", () => {
    const dir = setupCase("json", {
      "package.json": JSON.stringify({
        dependencies: { lodash: "1.0.0" },
      }),
      "policy.json": JSON.stringify(policy),
      "licenses.json": JSON.stringify(licenses),
    });

    const result = spawnSync({
      cmd: [
        "bun",
        "run",
        cliPath,
        "--manifest",
        "package.json",
        "--policy",
        "policy.json",
        "--licenses",
        "licenses.json",
        "--format",
        "json",
      ],
      cwd: dir,
    });

    expect(result.exitCode).toBe(0);
    const parsed = JSON.parse(result.stdout.toString()) as {
      summary: { total: number; approved: number };
    };
    expect(parsed.summary.total).toBe(1);
    expect(parsed.summary.approved).toBe(1);
  });
});

