interface Args {
  manifest: string;
  policy: string;
  licenses?: string;
  format: Format;
  reportFile?: string;
  failOn: Set<Status>;
}

function parseArgs(argv: string[]): Args {
  const args: Partial<Args> & { failOnRaw?: string } = { format: "text" };
  for (let i = 0; i < argv.length; i++) {
    const flag = argv[i];
    const value = argv[i + 1];
    switch (flag) {
      case "--manifest":
        args.manifest = value;
        i++;
        break;
      case "--policy":
        args.policy = value;
        i++;
        break;
      case "--licenses":
        args.licenses = value;
        i++;
        break;
      case "--format":
        if (value !== "text" && value !== "json") {
          throw new Error(`--format must be 'text' or 'json' (got '${value}')`);
        }
        args.format = value;
        i++;
        break;
      case "--report-file":
        args.reportFile = value;
        i++;
        break;
      case "--fail-on":
        args.failOnRaw = value;
        i++;
        break;
      default:
        throw new Error(`Unknown flag: ${flag}`);
    }
  }
  if (!args.manifest) throw new Error("--manifest is required");
  if (!args.policy) throw new Error("--policy is required");
  const failOn = new Set<Status>(
    (args.failOnRaw ?? "denied,unknown")
      .split(",")
      .map((s) => s.trim())
      .filter(Boolean) as Status[],
  );
  return {
    manifest: args.manifest!,
    policy: args.policy!,
    licenses: args.licenses,
    format: args.format!,
    reportFile: args.reportFile,
    failOn,
  };
}

function readJson<T>(path: string, label: string): T {
  if (!existsSync(path)) {
    throw new Error(`${label} file '${path}' not found`);
  }
  const text = readFileSync(path, "utf8");
