  testCase: {
    label: string;
    manifest: string;
    policy: string;
    licenses: string;
    expected_exit_code: number;
    expected_summary: string;
  };
  // Strings that MUST appear verbatim in act's combined stdout/stderr.
  expectInOutput: string[];
}

